// _Bool への複合代入 (`b += ...` 等) の結果が 0/1 に正規化されないバグ。
// 通常代入 `b = v` は正規化 (v != 0) されるが、複合代入は op の結果をそのまま
// 格納していたため、`_Bool b=1; b+=10;` が 11 になっていた。
// C11 6.3.1.2: _Bool への代入は 0/1 に正規化される。
// 修正前: exit=11 等
// 期待: exit=42
int main(void) {
    _Bool a = 1;  a += 10;   // (1+10)!=0 -> 1
    _Bool b = 0;  b |= 4;    // (0|4)!=0  -> 1
    _Bool c = 1;  c <<= 5;   // (1<<5)!=0 -> 1
    _Bool d = 1;  d -= 1;    // (1-1)==0  -> 0
    _Bool e = 3;  e *= 0;    // 0         -> 0
    // a..c = 1, d,e = 0
    return (a && b && c && !d && !e) ? 42 : 0;
}
